The screen shows a p5.js editor, likely within an online IDE like the p5.js web editor. The filename is `sketch.js`. A canvas preview area displays a dark background with several white arcs arranged in a semi-circular pattern along the bottom edge, and two smaller circles above them. The code editor contains JavaScript code that appears to be drawing these arcs using `arc()` and `circle()`.

```javascript
let x = 0, y = 100;

function setup() {
  createCanvas(400, 400);
  angleMode(DEGREES);
}

function draw() {
  background(0, 0, 35);
  x = x + 3;

  function ufo(x, y) {
    push();
    noStroke();
    translate(x, y);
    // draw top half
    fill(120, 120, 150);
    arc(0, 0, 100, 30, 180, 0);
    arc(0, 0, 50, 50, 180, 0);
    // draw bottom half
    fill(30, 30, 80);
    arc(0, 0, 100, 30, 0, 180);
    arc(0, 0, 50, 50, 0, 180);
    for (let x = -50; x <= 50; x += 10) {
      circle(x, 0, 5);
    }
    pop();
  }

  ufo(x, y);
}
```

The UI shows play/pause buttons, an auto-refresh toggle, and a "Console" area at the bottom. The code is currently stopped (pause button highlighted).  The editor also indicates that the file was saved 1 minute ago.

